// Əsas switch nümunəsi
const day = 'Çərşənbə';
switch (day) {
  case 'Bazar ertəsi':
    console.log('Həftə başlayır!');
    break;
  case 'Çərşənbə':
    console.log('Həftənin ortasıdır.');
    break;
