// Пример базового switch
const day = 'Среда';
switch (day) {
  case 'Понедельник':
    console.log('Неделя начинается!');
    break;
  case 'Среда':
    console.log('Середина недели!');
    break;
  case 'Пятница':
    console.log('Почти выходные!');
    break;
  default:
    console.log('Другой день.');
}
// Вывод: Середина недели!

// Пример без break
const fruit = 'Яблоко';
switch (fruit) {
  case 'Яблоко':
    console.log('Это яблоко.');
  case 'Груша':
    console.log('Это груша.');
  default:
    console.log('Другой фрукт.');
}
// Вывод:
// Это яблоко.
// Это груша.
// Другой фрукт.

// Правильный пример с break
switch (fruit) {
  case 'Яблоко':
    console.log('Это яблоко.');
    break;
  case 'Груша':
    console.log('Это груша.');
    break;
  default:
    console.log('Другой фрукт.');
}
// Вывод: Это яблоко.

// Пример с default
const grade = 'B';
switch (grade) {
  case 'A':
    console.log('Отличный результат!');
    break;
  case 'B':
    console.log('Хороший результат!');
    break;
  case 'C':
    console.log('Удовлетворительный результат.');
    break;
  default:
    console.log('Оценка не введена.');
}
// Вывод: Хороший результат!

// Пример с несколькими case
const day = 'Суббота';
switch (day) {
  case 'Суббота':
  case 'Воскресенье':
    console.log('Это выходной!');
    break;
  case 'Понедельник':
  case 'Среда':
  case 'Пятница':
    console.log('Это рабочий день.');
    break;
  default:
    console.log('Неизвестный день.');
}
// Вывод: Это выходной!

// Пример с ошибкой
// Ошибка: Отсутствие break
const number = 2;
switch (number) {
  case 1:
    console.log('Один');
  case 2:
    console.log('Два');
  case 3:
    console.log('Три');
  default:
    console.log('Другое число');
}
// Вывод:
// Два
// Три
// Другое число

// Правильный подход
switch (number) {
  case 1:
    console.log('Один');
    break;
  case 2:
    console.log('Два');
    break;
  case 3:
    console.log('Три');
    break;
  default:
    console.log('Другое число');
}
// Вывод: Два

// Пример с switch
const month = 'Январь';
switch (month) {
  case 'Январь':
    console.log('Зимний месяц');
    break;
  case 'Июль':
    console.log('Летний месяц');
    break;
  default:
    console.log('Другой месяц');
}
// Вывод: Зимний месяц

// Тот же пример с if-else
if (month === 'Январь') {
  console.log('Зимний месяц');
} else if (month === 'Июль') {
  console.log('Летний месяц');
} else {
  console.log('Другой месяц');
}
// Вывод: Зимний месяц

